func:
// Runs when a "Get …" node throws (e.g. entity_id does not exist) or the model
// node itself throws. A caught error message carries none of msg.temp/soc/etc.,
// so this builds the same zeroed shape as calc-model's isNaN fail-closed branch
// from scratch — see tools/nodered-flow.json "Four-zone model" node and CLAUDE.md.
const CONF_KEYS = ["p50", "p75", "p90", "p95"];

const reason = `Node error: ${msg.error && msg.error.message ? msg.error.message : "unknown error"}`;
node.error(reason, msg);

const zeroResult = { safe_export: 0, consumption: 0, buffer: 0, total_needed: 0, grid_needed: 0 };
const results = {};
for (const key of CONF_KEYS) results[key] = { ...zeroResult };

msg.result = {
    zone: "error",
    temp: null,
    humidity: null,
    solcast_kwh: null,
    soc: null,
    min_soc: null,
    available_kwh: 0,
    model_info: reason,
    reason,
    ...results,
    updated_at: new Date().toISOString(),
};
msg.payload = 0;

return msg;

// ── Model coefficients ────────────────────────────────────────────────
const BATTERY_KWH = 13.8;

// Heating zone (temp < 17°C)
const H      = { b0: 22.5759, b1: -0.9593, b2: -0.016243 };
const H_P95  = 2.649;

// Heating zone fallback (Solcast unavailable): temp-only OLS
const H_TEMP_ONLY = { b0: 22.4741, b1: -1.0043 };

// Warm boundary zone (17–19°C): empirical percentile table
const WARM = { p50: 5.979, p75: 6.808, p90: 7.783, p95: 8.783 };

// Mild zone (19–21°C): empirical percentile table
const MILD = { p50: 6.796, p75: 7.840, p90: 8.514, p95: 9.002 };

// Cooling zone (temp > 21°C)
const C      = { b0: -9.6822, b1: 0.7163, b2: 0.028676 };
const C_P95  = 2.431;

// Cooling zone fallback (humidity unavailable): temp-only OLS
const C_TEMP_ONLY = { b0: -5.1760, b1: 0.5965 };

// Floor on the OLS point estimate (heating/cooling zones only) — mirrors
// src/model.py MIN_CONSUMPTION_KWH. Keep in sync (see CLAUDE.md).
const MIN_CONSUMPTION_KWH = 1;

// Confidence levels: fraction of P95 buffer to apply
const CONF = [
    { key: "p50", label: "P50", scale: 0.33 },
    { key: "p75", label: "P75", scale: 0.58 },
    { key: "p90", label: "P90", scale: 0.88 },
    { key: "p95", label: "P95", scale: 1.00 },
];

// ── Inputs ────────────────────────────────────────────────────────────
const temp       = parseFloat(msg.temp);
const humidity   = parseFloat(msg.humidity);
const solcastKwh = parseFloat(msg.solcast_kwh);
const soc        = parseFloat(msg.soc);
const minSoc     = parseFloat(msg.minSoc);

// ── Fail closed: temp/soc/minSoc are hard-required. Solcast and humidity
// are soft-required — missing either falls back to a temp-only model
// variant instead of failing (mirrors src/model.py _predict_consumption).
if ([temp, soc, minSoc].some(isNaN)) {
    const reason = "One or more required sensor values (temp, soc, minSoc) are unavailable or NaN";
    node.error(reason, msg);

    const zeroResult = { safe_export: 0, consumption: 0, buffer: 0, total_needed: 0, grid_needed: 0 };
    const results = {};
    for (const conf of CONF) results[conf.key] = { ...zeroResult };

    msg.result = {
        zone: "error",
        temp: isNaN(temp) ? null : temp,
        humidity: isNaN(humidity) ? null : humidity,
        solcast_kwh: isNaN(solcastKwh) ? null : solcastKwh,
        soc: isNaN(soc) ? null : soc,
        min_soc: isNaN(minSoc) ? null : minSoc,
        available_kwh: 0,
        model_info: reason,
        reason,
        ...results,
        updated_at: new Date().toISOString(),
    };
    msg.payload = 0;
    return msg;
}

// ── Zone determination ────────────────────────────────────────────────
let zone;
if (temp < 17)       zone = "heating";
else if (temp < 19)  zone = "warm_boundary";
else if (temp <= 21) zone = "mild";
else                 zone = "cooling";

// ── Per-zone base consumption and P95 buffer (kWh internally) ────────
let baseConsumption, p95Buffer, modelInfo, empiricalTable;

if (zone === "heating") {
    if (!isNaN(solcastKwh)) {
        baseConsumption = H.b0 + H.b1 * temp + H.b2 * solcastKwh;
        p95Buffer       = H_P95;
        empiricalTable  = null;
        modelInfo       = `Heating (<17°C): ${H.b0} + (${H.b1}×${temp}) + (${H.b2}×${solcastKwh.toFixed(1)}kWh)`;
    } else {
        baseConsumption = H_TEMP_ONLY.b0 + H_TEMP_ONLY.b1 * temp;
        p95Buffer       = H_P95;
        empiricalTable  = null;
        modelInfo       = `Heating temp-only (<17°C, no Solcast): ${H_TEMP_ONLY.b0} + (${H_TEMP_ONLY.b1}×${temp})`;
    }

} else if (zone === "warm_boundary") {
    empiricalTable  = WARM;
    p95Buffer       = 0;
    modelInfo       = `Warm boundary (17–19°C): empirical percentile table`;

} else if (zone === "mild") {
    empiricalTable  = MILD;
    p95Buffer       = 0;
    modelInfo       = `Mild (19–21°C): empirical percentile table`;

} else {
    if (!isNaN(humidity)) {
        baseConsumption = C.b0 + C.b1 * temp + C.b2 * humidity;
        p95Buffer       = C_P95;
        empiricalTable  = null;
        modelInfo       = `Cooling (>21°C): ${C.b0} + (${C.b1}×${temp}) + (${C.b2}×${humidity}%)`;
    } else {
        baseConsumption = C_TEMP_ONLY.b0 + C_TEMP_ONLY.b1 * temp;
        p95Buffer       = C_P95;
        empiricalTable  = null;
        modelInfo       = `Cooling temp-only (>21°C, no humidity): ${C_TEMP_ONLY.b0} + (${C_TEMP_ONLY.b1}×${temp})`;
    }
}

// ── Compute result for each confidence level ──────────────────────────
const availableKwh = ((soc - minSoc) / 100) * BATTERY_KWH;
const results = {};

for (const conf of CONF) {
    let consumption, buffer;

    if (empiricalTable) {
        consumption = empiricalTable[conf.key];
        buffer      = 0;
    } else {
        buffer      = p95Buffer * conf.scale;
        consumption = Math.max(MIN_CONSUMPTION_KWH, baseConsumption);
    }

    const totalNeeded = consumption + buffer;
    const gridNeeded  = Math.max(0, totalNeeded - availableKwh);
    const exportableWh = Math.round(Math.max(0, availableKwh - totalNeeded) * 1000);

    results[conf.key] = {
        consumption:    parseFloat(consumption.toFixed(3)),
        buffer:         parseFloat(buffer.toFixed(3)),
        total_needed:   parseFloat(totalNeeded.toFixed(3)),
        grid_needed:    parseFloat(gridNeeded.toFixed(3)),
        safe_export: exportableWh,
    };
}

// ── Build output message ──────────────────────────────────────────────
msg.result = {
    zone,
    temp,
    humidity:      isNaN(humidity) ? null : humidity,
    solcast_kwh:   isNaN(solcastKwh) ? null : solcastKwh,
    soc,
    min_soc:       minSoc,
    available_kwh: parseFloat(availableKwh.toFixed(3)),
    model_info:    modelInfo,
    ...results,
    updated_at:      new Date().toISOString(),
};

// Primary export value: P50 in Wh
msg.payload = results.p50.safe_export;

node.log(`Zone: ${zone} | Temp: ${temp}°C | SOC: ${soc}% | P50 export: ${results.p50.safe_export} Wh (avail: ${availableKwh.toFixed(2)} kWh)`);

return msg;

// input_text max length is 255 chars — keep it tight
const r = msg.result;
const compact = {
  zone: r.zone,
  temp: r.temp,
  soc: r.soc,
  avail_kwh: r.available_kwh,
  needed_kwh: r.p50.total_needed,
  p50: r.p50.safe_export,
  p75: r.p75.safe_export,
  p90: r.p90.safe_export,
  p95: r.p95.safe_export,
  at: r.updated_at,
};
msg.payload = JSON.stringify(compact);
return msg;
